+function deriveConnectionToken(tunnelId: string): string {
+    const hash = createHash('sha256');
+    hash.update(tunnelId);
+    let result = hash.digest('base64url');
+    if (result.startsWith('-')) {
+        result = 'a' + result;
+    }
+    return result;
+}", 'advice': '审查隧道agent host的安全模型。如果隧道连接需要令牌，则应从隧道信息中派生令牌（例如，使用与TypeScript服务相同的算法），并将其设置在 `AgentHostConfig` 的 `connection_token` 字段中，或者确保 `without_connection_token: true` 是预期且安全的行为。可能需要查阅相关协议文档或与其他部分（如CLI隧道启动逻辑）保持一致。', 'confidence': 0.6, 'relevance': 0.3, 'severity': 'Medium'}]

